#include <iostream>
#include <vector>
#include <string>
#include <sstream>
#include <streambuf>

// Forward declaration of the solution's core logic function.
void solve_4778();

// Helper function to simulate running the solution's logic
// by redirecting standard input and output.
std::string run_solution_and_get_output(const std::string& input_str, void (*solution_func)() = solve_4778) {
    std::stringstream ss_input(input_str);
    std::stringstream ss_output;

    std::streambuf* old_cin_buf = std::cin.rdbuf();
    std::streambuf* old_cout_buf = std::cout.rdbuf();

    std::cin.rdbuf(ss_input.rdbuf());
    std::cout.rdbuf(ss_output.rdbuf());

    solution_func();

    std::cin.rdbuf(old_cin_buf);
    std::cout.rdbuf(old_cout_buf);

    return ss_output.str();
}

int main() {
    std::vector<std::pair<std::string, std::string>> test_cases = {
        { "10", "The sum of odd numbers between 1 and 10 is: 25\n" },
        { "1", "The sum of odd numbers between 1 and 1 is: 1\n" },
        { "2", "The sum of odd numbers between 1 and 2 is: 1\n" },
        { "100", "The sum of odd numbers between 1 and 100 is: 2500\n" }
    };

    bool all_passed = true;
    for (size_t i = 0; i < test_cases.size(); ++i) {
        const auto& tc = test_cases[i];
        std::string actual_output = run_solution_and_get_output(tc.first);

        if (actual_output == tc.second) {
            // Test passed, no output needed for success
        } else {
            std::cout << "Test " << i + 1 << " Failed." << std::endl;
            std::cout << "Input: \"" << tc.first << "\"" << std::endl;
            std::cout << "Expected: \"" << tc.second << "\"" << std::endl;
            std::cout << "Got: \"" << actual_output << "\"" << std::endl;
            all_passed = false;
        }
    }

    if (all_passed) {
        return 0;
    } else {
        return 1;
    }
}
